async function testGetDirectionsValidation() {
  // Test missing parameters — should return 400
  const res1 = await fetch('/api/directions');
  assertEquals(res1.status, 400, 'Missing params should return 400');
  const body1 = await res1.json();
  assert(body1.error === true, 'Should have error flag');

  // Test invalid coordinates — out of range
  const res2 = await fetch('/api/directions?lat=-100&lon=5');
  assertEquals(res2.status, 400, 'Out of range lat should return 400');

  // Test non-numeric params
  const res3 = await fetch('/api/directions?lat=abc&lon=xyz');
  assertEquals(res3.status, 400, 'Non-numeric params should return 400');
}
